#include <algorithm>
#include <ranges>
#include <vector>
#include <string>
#include <iostream>

struct Employee {
    std::string name;
    int salary;
};

int main() {
    std::vector<int> nums = {5, 2, 8, 1, 9, 3};

    // std::ranges::sort принимает range целиком
    std::ranges::sort(nums);
    std::cout << "sorted: ";
    for (int x : nums) std::cout << x << ' ';
    std::cout << '\n';

    // find
    auto it = std::ranges::find(nums, 8);
    std::cout << "found 8: " << (it != nums.end() ? "yes" : "no") << '\n';

    // Проекция: сортировка сотрудников по зарплате
    std::vector<Employee> team = {
        {"Alice", 90000}, {"Bob", 75000}, {"Carol", 82000}
    };
    std::ranges::sort(team, {}, &Employee::salary);
    std::cout << "by salary: ";
    for (const auto& e : team) std::cout << e.name << '(' << e.salary << ") ";
    std::cout << '\n';

    // max_element с проекцией
    auto top = std::ranges::max_element(team, {}, &Employee::salary);
    std::cout << "highest paid: " << top->name << '\n';
}

#include <algorithm>
#include <ranges>
#include <concepts>
#include <vector>
#include <list>
#include <iostream>

// Алгоритм для любого input_range
template<std::ranges::input_range R>
auto sum_range(const R& r) {
    std::ranges::range_value_t<R> total{};
    for (const auto& x : r) total += x;
    return total;
}

// Алгоритм, требующий random_access (индексированный доступ)
template<std::ranges::random_access_range R>
auto range_median(R r) {
    std::ranges::sort(r);
    return r[r.size() / 2];
}

int main() {
    std::vector<int> v = {1, 2, 3, 4, 5, 6, 7};
    std::list<int> l = {10, 20, 30};

    std::cout << "sum(vector): " << sum_range(v) << '\n';
    std::cout << "sum(list):   " << sum_range(l) << '\n';

    std::cout << "median(vector): " << range_median(v) << '\n';
    // range_median(l) не скомпилируется — list не random_access

    // count_if
    std::cout << "count >= 4: " << std::ranges::count_if(v, [](int x){ return x >= 4; }) << '\n';

    // copy_if
    std::vector<int> dest;
    std::ranges::copy_if(v, std::back_inserter(dest), [](int x){ return x % 2 == 0; });
    std::cout << "evens: ";
    for (int x : dest) std::cout << x << ' ';
    std::cout << '\n';

    // Проверка концептов
    std::cout << "vector is random_access: " << std::ranges::random_access_range<decltype(v)> << '\n';
    std::cout << "list is random_access:   " << std::ranges::random_access_range<decltype(l)> << '\n';
}
